//--------------------------------------------------------------------------
//  Enums — mirror the DLX enumeration values set in Block Styler
//--------------------------------------------------------------------------
enum class StartPointMode
{
    BodyCenterTop    = 0,
    BodyCenter       = 1,
    BodyCenterBottom = 2,
    FaceCenter       = 3
};

enum class FinishPointMode
{
    AbsOrigin  = 0,
    WcsOrigin  = 1,
    BodyCenter = 2,
    FaceCenter = 3,
    XZero      = 4,
    YZero      = 5,
    ZZero      = 6
};

//--------------------------------------------------------------------------
//  DLX path resolution — look beside the DLL first, fall back to raw name
//--------------------------------------------------------------------------
extern "C" IMAGE_DOS_HEADER __ImageBase;

std::string GetDllDirectory()
{
    char buffer[MAX_PATH] = {0};
    HMODULE module = reinterpret_cast<HMODULE>(&__ImageBase);
    DWORD length = GetModuleFileNameA(module, buffer, MAX_PATH);
    if (length == 0 || length >= MAX_PATH)
        return ".";

    std::string path(buffer);
    size_t slash = path.find_last_of("\\/");
    return slash == std::string::npos ? "." : path.substr(0, slash);
}

std::string ResolveDlxPath(const char* dlxName)
{
    std::string deployedPath = GetDllDirectory() + "\\" + dlxName;
    if (GetFileAttributesA(deployedPath.c_str()) != INVALID_FILE_ATTRIBUTES)
        return deployedPath;
    return dlxName;
}

//--------------------------------------------------------------------------
//  Geometry helpers
//--------------------------------------------------------------------------
double VectorLength(const Vector3d& v)
{
    return std::sqrt(v.X * v.X + v.Y * v.Y + v.Z * v.Z);
}

Point3d AskBoxCenter(tag_t objectTag)
{
    double box[6] = {0.0};
    int err = UF_MODL_ask_bounding_box(objectTag, box);
    if (err != 0)
    {
        std::ostringstream ss;
        ss << "读取包围盒失败，错误码 " << err;
        throw std::runtime_error(ss.str());
    }
    return Point3d((box[0] + box[3]) * 0.5,
                   (box[1] + box[4]) * 0.5,
                   (box[2] + box[5]) * 0.5);
}

Point3d AskBodyPoint(tag_t bodyTag, StartPointMode mode)
{
    double box[6] = {0.0};
    int err = UF_MODL_ask_bounding_box(bodyTag, box);
    if (err != 0)
    {
        std::ostringstream ss;
        ss << "读取体包围盒失败，错误码 " << err;
        throw std::runtime_error(ss.str());
    }

    double cx = (box[0] + box[3]) * 0.5;
    double cy = (box[1] + box[4]) * 0.5;
    switch (mode)
    {
        case StartPointMode::BodyCenterTop:
            return Point3d(cx, cy, box[5]);
        case StartPointMode::BodyCenterBottom:
            return Point3d(cx, cy, box[2]);
        default: // BodyCenter
            return Point3d(cx, cy, (box[2] + box[5]) * 0.5);
    }
}

//--------------------------------------------------------------------------
//  Tag resolution helpers
//--------------------------------------------------------------------------
tag_t ResolveBodyTag(TaggedObject* obj)
{
    if (!obj) return NULL_TAG;

    if (auto* body = dynamic_cast<Body*>(obj))
        return body->Tag();
    if (auto* face = dynamic_cast<Face*>(obj))
    {
        Body* b = face->GetBody();
        return b ? b->Tag() : face->Tag();
    }
    if (auto* edge = dynamic_cast<Edge*>(obj))
    {
        Body* b = edge->GetBody();
        return b ? b->Tag() : edge->Tag();
    }
    return obj->Tag();
}

//--------------------------------------------------------------------------
//  Selection helpers
//--------------------------------------------------------------------------
std::vector<tag_t> CollectTransformTags(BlockStyler::SelectObject* sel)
{
    std::vector<tag_t> tags;
    if (!sel) return tags;

    std::set<tag_t> unique;
    for (auto* obj : sel->GetSelectedObjects())
    {
        tag_t t = ResolveBodyTag(obj);
        if (t != NULL_TAG && unique.insert(t).second)
            tags.push_back(t);
    }
    return tags;
}

TaggedObject* PrimarySelection(BlockStyler::SelectObject* sel)
{
    if (!sel) return nullptr;
    auto objects = sel->GetSelectedObjects();
    return objects.empty() ? nullptr : objects.front();
}

//--------------------------------------------------------------------------
//  Point resolution
//--------------------------------------------------------------------------
Point3d ResolveStartPoint(StartPointMode mode,
                          TaggedObject* primary,
                          BlockStyler::SpecifyPoint* manualPt)
{
    if (!primary)
        throw std::runtime_error("请先选择操作对象");

    if (mode == StartPointMode::FaceCenter)
    {
        if (auto* face = dynamic_cast<Face*>(primary))
            return AskBoxCenter(face->Tag());
        if (manualPt)
            return manualPt->Point();
        throw std::runtime_error("起始点为面中心时，请选择面或手动指定点");
    }

    tag_t bodyTag = ResolveBodyTag(primary);
    if (bodyTag == NULL_TAG)
        throw std::runtime_error("无法从选择对象解析体");
    return AskBodyPoint(bodyTag, mode);
}

Point3d ResolveFinishPoint(FinishPointMode mode,
                           TaggedObject* primary,
                           const Point3d& startPt,
                           Session* session,
                           BlockStyler::SpecifyPoint* manualPt)
{
    Part* workPart = session->Parts()->Work();

    switch (mode)
    {
        case FinishPointMode::AbsOrigin:
            return Point3d(0.0, 0.0, 0.0);

        case FinishPointMode::WcsOrigin:
            if (workPart && workPart->WCS())
                return workPart->WCS()->Origin();
            return Point3d(0.0, 0.0, 0.0);

        case FinishPointMode::BodyCenter:
        {
            if (!primary)
                throw std::runtime_error("结束点为体中心时，请选择操作对象");
            tag_t t = ResolveBodyTag(primary);
            return AskBoxCenter(t);
        }

        case FinishPointMode::FaceCenter:
        {
            if (auto* face = dynamic_cast<Face*>(primary))
                return AskBoxCenter(face->Tag());
            if (manualPt)
                return manualPt->Point();
            throw std::runtime_error("结束点为面中心时，请选择面或手动指定点");
        }

        case FinishPointMode::XZero:
            return Point3d(0.0, startPt.Y, startPt.Z);
        case FinishPointMode::YZero:
            return Point3d(startPt.X, 0.0, startPt.Z);
        case FinishPointMode::ZZero:
            return Point3d(startPt.X, startPt.Y, 0.0);

        default:
            throw std::runtime_error("未知的结束点模式");
    }
}

//--------------------------------------------------------------------------
//  Transform execution — move uses UF_MODL_transform_entities,
//  copy uses UF_TRNS (uf5947)
//--------------------------------------------------------------------------
std::string StatusText(int status)
{
    switch (status)
    {
        case 0:  return "成功";
        case 1:  return "对象数量无效";
        case 2:  return "变换参数无效";
        case 3:  return "对象无效或不可变换";
        case 4:  return "对象不支持当前矩阵";
        case 5:  return "建模更新失败";
        case 6:  return "复制实体添加建模数据失败";
        case 7:  return "不能缩放参数化实体";
        case 8:  return "变换矩阵不适用于对象";
        case 9:  return "不能缩放展开曲线";
        case 10: return "不能镜像实体";
        case 11: return "不能变换装配 occurrence";
        case 12: return "不能变换草图或草图曲线";
        default: return "未知错误";
    }
}

void ExecuteMoveCopy(const std::vector<tag_t>& objectTags,
                     const Vector3d& translation,
                     bool isCopy)
{
    if (objectTags.empty())
        throw std::runtime_error("请选择操作对象");

    double tol = 1.0e-9;
    if (VectorLength(translation) < tol)
        throw std::runtime_error("起始点和结束点重合，不能执行零向量移动/复制");

    if (!isCopy)
    {
        // --- Move: 4×4 transformation matrix ---
        double matrix[16] = {
            1.0, 0.0, 0.0, translation.X,
            0.0, 1.0, 0.0, translation.Y,
            0.0, 0.0, 1.0, translation.Z,
            0.0, 0.0, 0.0, 1.0
        };

        std::vector<tag_t> ents = objectTags;
        int err = UF_MODL_transform_entities(
            static_cast<int>(ents.size()), ents.data(), matrix);
        if (err != 0)
        {
            std::ostringstream ss;
            ss << "移动失败，UF_MODL_transform_entities 错误码 " << err;
            throw std::runtime_error(ss.str());
        }
        return;
    }

    // --- Copy: UF_TRNS path ---
    double delta[3] = {translation.X, translation.Y, translation.Z};
    double matrix[12] = {0.0};
    uf5943(delta, matrix);

    int objCount = static_cast<int>(objectTags.size());
    int copyFlag = 2;            // UF_TRNS_copy
    int destLayer = 0;
    int traceCurves = 2;         // no trace
    int status = 0;
    tag_t traceGroup = NULL_TAG;
    std::vector<tag_t> copies(objectTags.size(), NULL_TAG);

    uf5947(matrix, const_cast<tag_t*>(objectTags.data()),
           &objCount, &copyFlag, &destLayer, &traceCurves,
           copies.data(), &traceGroup, &status);

    if (status != 0)
    {
        std::ostringstream ss;
        ss << "复制失败，UF_TRNS 状态码 " << status
           << "：" << StatusText(status);
        throw std::runtime_error(ss.str());
    }
}

