//------------------------------------------------------------------------------
//  update_cb — handle UI interactions
//------------------------------------------------------------------------------
int diancm::update_cb(BlockStyler::UIBlock* block)
{
    try
    {
        if (block == button0)
        {
            m_opMode = OpMode::Move;
        }
        else if (block == button01)
        {
            m_opMode = OpMode::Copy;
        }
        else if (block == selection0)
        {
            UpdateStartPointUI();
        }
        else if (block == enum0)
        {
            // start point mode changed
        }
        else if (block == enum01)
        {
            // end point mode changed
        }
        else if (block == point0)
        {
            m_startPtClicked = true;
        }
        else if (block == point01)
        {
            m_endPtSpecified = true;
        }
        else if (block == toggle0)
        {
            UpdateStartPointUI();
        }
    }
    catch (const exception& ex)
    {
        diancm::theUI->NXMessageBox()->Show(
            "Block Styler", NXMessageBox::DialogTypeError, ex.what());
    }
    return 0;
}

//------------------------------------------------------------------------------
//  apply_cb — core logic: resolve points → execute transform
//------------------------------------------------------------------------------
int diancm::apply_cb()
{
    int errorCode = 0;
    Session::UndoMarkId undoMark = theSession->SetUndoMark(
        Session::MarkVisibilityVisible, "点选择移动/复制");

    try
    {
        if (m_opMode == OpMode::None)
            throw std::runtime_error("请先点击「移动」或「复制」按钮选择操作模式");

        TaggedObject* primary = PrimarySelection(selection0);
        if (!primary)
            throw std::runtime_error("请选择操作对象");

        std::vector<tag_t> selectedTags = CollectTransformTags(selection0);
        if (selectedTags.empty())
            throw std::runtime_error("未选中有效体对象");

        // Resolve start point — manual point overrides enum mode
        Point3d start;
        if (m_startPtSpecified && point0)
        {
            start = point0->Point();
        }
        else
        {
            auto startMode = static_cast<StartPointMode>(GetEnumValue(enum0));
            start = ResolveStartPoint(startMode, primary, point0);
        }

        // Resolve end point — manual point overrides enum mode
        Point3d finish;
        if (m_endPtSpecified && point01)
        {
            finish = point01->Point();
        }
        else
        {
            auto finishMode = static_cast<FinishPointMode>(GetEnumValue(enum01));
            finish = ResolveFinishPoint(finishMode, primary, start, theSession, point01);
        }
        Vector3d translation(finish.X - start.X,
                             finish.Y - start.Y,
                             finish.Z - start.Z);

        ExecuteMoveCopy(selectedTags, translation,
                        m_opMode == OpMode::Copy);

        theSession->UpdateManager()->DoUpdate(undoMark);
    }
    catch (const NXException& ex)
    {
        errorCode = 1;
        theSession->UndoToMark(undoMark, "点选择移动/复制");
        diancm::theUI->NXMessageBox()->Show(
            "错误", NXMessageBox::DialogTypeError, ex.Message());
    }
    catch (const std::exception& ex)
    {
        errorCode = 1;
        theSession->UndoToMark(undoMark, "点选择移动/复制");
        diancm::theUI->NXMessageBox()->Show(
            "提示", NXMessageBox::DialogTypeInformation, ex.what());
    }

    return errorCode;
}

//------------------------------------------------------------------------------
//  ok_cb — delegates to apply_cb
//------------------------------------------------------------------------------
int diancm::ok_cb()
{
    int errorCode = 0;
    try
    {
        errorCode = apply_cb();
    }
    catch (const exception& ex)
    {
        errorCode = 1;
        diancm::theUI->NXMessageBox()->Show(
            "Block Styler", NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

